import{_ as a}from"./chunks/collection.68ea7ba2.js";import{_ as o,o as i,c as n,e as s,b as r}from"./app.83d10e71.js";import"./chunks/index.57bdae95.js";import"./chunks/wikipedia-w.902ff695.js";import"./chunks/theory.0c9b7d93.js";import"./chunks/chroma.b06812a2.js";import"./chunks/row.82007c2c.js";import"./chunks/keys.ee48e8ce.js";import"./chunks/render.ea11c60f.js";import"./chunks/svg-save.28541c60.js";const D='{"title":"Diatonic scales","description":"","frontmatter":{"title":"Diatonic scales","subtitle":"The seven 7-notes set rotations","date":"2021-09-15T00:00:00.000Z","diatonic":{"major":{"title":"Major","chroma":"101011010101","description":"Also known as the Ionian mode, the major scale consists of the seven distinct notes in a scale (C D E F G A B) and an eighth note that reproduces the first one in a higher octave. The first, third, and fifth degrees form a chord known as a major triad, which can be found in related major scales, like the harmonic major scale, which has a minor sixth triad. The melodic major scale, also known as the Aeolian dominant scale, has lowered sixth and seventh degrees."},"dorian":{"title":"Dorian","chroma":"101101010110","description":"The modern Dorian mode, also known as the Russian mode, is built around the D note, the second note on the major scale. Music experts consider it a minor chord because its third note is a minor third, meaning that it\u2019s lowered by a half step and a flattened seventh note, which results in a melancholy sound."},"phrygian":{"title":"Phrygian","chroma":"110101011010","description":"The Phrygian scale, which begins on the E note, the third on the major scale, and ends at E major, is considered a minor chord due to its abundance of minor notes (second, third, sixth, and seventh), and as such, is infrequently used. Its dominant sound is somewhat exotic; flamenco music from Spain is often written in Phrygian mode."},"lydian":{"title":"Lydian","chroma":"101010110101","description":"The fourth mode, Lydian, is a bright-sounding mode that begins with the F note. It\u2019s similar to the major scale with one exception: its fourth scale degree is raised by a semitone."},"myxolydian":{"title":"Myxolydian","chroma":"101011010110","description":"Also known as the dominant mode, the fifth mode, Mixolydian, covers G to G major on the keyboard and, like the Lydian mode, very similar to the major scale save for its seventh note, which is lowered by a semitone. Jazz and blues make excellent use of the Mixolydian mode."},"minor":{"title":"Minor","chroma":"101101011010","description":"The Aeolian, or natural minor mode, opens with the A note on the white keys of a piano keyboard, and follows the same scale degrees as the major scale, except for its minor third. Like the Dorian mode, it has a melancholy sound with an extra degree of sadness."},"locarian":{"title":"Locrian","chroma":"110101101010","description":"The seventh and final mode, Locrian, is also one of the least employed modes due to its dark and minor sound built around the B note. Like the Dorian, Aeolian, and Phrygian, the Locrian has a minor third, but also a minor second and fifth; the latter gives the mode a sense of being interrupted or unfinished. "}}},"headers":[{"level":2,"title":"What Is a Diatonic Scale?","slug":"what-is-a-diatonic-scale"},{"level":3,"title":"Tones","slug":"tones"},{"level":3,"title":"Letter names","slug":"letter-names"},{"level":3,"title":"Scales","slug":"scales"},{"level":2,"title":"Tonic - the root note","slug":"tonic-the-root-note"},{"level":2,"title":"The 7 Modes of the Diatonic Scale","slug":"the-7-modes-of-the-diatonic-scale"}],"relativePath":"theory/scales/diatonic/index.md"}',h={},c=r("",11);function d(e,l,m,f,u,p){const t=a;return i(),n("div",null,[c,s(t,{collection:e.$frontmatter.diatonic},null,8,["collection"])])}var A=o(h,[["render",d]]);export{D as __pageData,A as default};
